+type Clause = (input: unknown) => { matched: boolean; value?: unknown };
+type Step = Clause | { tap: (result: unknown) => unknown };
+
+/**
+ * Creates a pattern matching expression which runs every matching clause.
+ * Calling without a value creates a reusable matcher; finish it with one of
+ * the `to*Function()` methods.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression(value, arguments.length === 1, []) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private input: input,
+    private hasInput: boolean,
+    private steps: readonly Step[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    const handler = args[args.length - 1] as (selection: unknown, value: input) => output;
+    const patterns: Pattern<input>[] = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+
+    const clause: Clause = (input) => {
+      let selected: Record<string, unknown> = {};
+      let hasSelections = false;
+      const select = (key: string, selectedValue: unknown) => {
+        hasSelections = true;
+        selected[key] = selectedValue;
+      };
+      const matched = patterns.some((pattern) => matchPattern(pattern, input, select)) &&
+        (!predicate || Boolean(predicate(input as input)));
+      if (!matched) return { matched: false };
+      const selections = hasSelections
+        ? symbols.anonymousSelectKey in selected ? selected[symbols.anonymousSelectKey] : selected
+        : input;
+      return { matched: true, value: handler(selections, input as input) };
+    };
+    return new MatchEachExpression(this.input, this.hasInput, [...this.steps, clause]);
+  }
+
+  when(predicate: (value: input) => unknown, handler: (value: input) => output): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.input, this.hasInput, [...this.steps, (input) =>
+      predicate(input as input) ? { matched: true, value: handler(input as input) } : { matched: false }
+    ]);
+  }
+
+  tap(callback: (result: output) => unknown): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.input, this.hasInput, [...this.steps, { tap: callback }]);
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType() { return this; }
+  narrow() { return this; }
+
+  toFunction(): (input: input) => output[] {
+    return (input) => this.evaluateOrThrow(input);
+  }
+
+  toExhaustiveFunction(): (input: input) => output[] {
+    return (input) => this.evaluateOrThrow(input);
+  }
+
+  toPartialFunction(): (input: input) => output[] | undefined {
+    return (input) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+
+  private evaluateOrThrow(input: input): output[] {
+    const results = this.evaluate(input);
+    if (!results.length) throw new NonExhaustiveError(input);
+    return results;
+  }
+
+  private evaluate(input: input): output[] {
+    const results: output[] = [];
+    for (const step of this.steps) {
